var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왜, 왜 이래? 설마 함선이 추락하는 건 아니겠지?","JPN":"な、何？　まさか艦船が墜落するんじゃないよね？","ENG":"W-what's going on? The ship's not really going down, right?","TWN":"怎…怎麼會這樣？艦船不會真的迫降吧？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"바닥이 기울어져.","JPN":"床が傾いてる。","ENG":"The floor is tilting.","TWN":"地板是傾斜的，"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"굴러 간다~","JPN":"転がる～","ENG":"I'm rolling awaaay.","TWN":"用滾的吧～"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"가긴 어딜 가! 이 바보야! 그러다 큰일나!","JPN":"どこ行くんだよ！　このバカ！　大怪我するかもしれないよ！","ENG":"What are you doing?! You're gonna hurt, you fool!","TWN":"是要滾去哪裡啦！你這個傻瓜！這樣會出事的！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"감속 장치는 작동하는 것 같지만 가속도가 점점 붙고 있어.","JPN":"減速装置は作動してるみたいだけど、どんどん加速度が増してる。","ENG":"The decelerator seems to be working, but we're still gaining speed.","TWN":"雖然有啟動減速裝置，但速度卻越來越快。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이 상태로 계속 가면 지면에 충돌할 때 우리 모두 도로시 다리 꼴이 날 거야.","JPN":"このままずっと行くと、地面に衝突する時にワタシたちもみんなドロシーの足のようになるはずだよ。","ENG":"At this rate, we're all going to end up like Dorothy's legs when it crashes into the ground.","TWN":"再這樣下去，撞到地面時，我們全都會像桃樂絲的腿一樣。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"자기가 이렇게 만들어 놓았으면서 말은……! 그럼 어서 빠져나가야지!","JPN":"自分がやっておきながら……！　じゃあ、早く抜け出ないと！","ENG":"Wow... You did this to me, you know? Whatever, let's get out of here then!","TWN":"就是你把我弄成這樣的還敢講……！還是快離開這裡吧！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"다들 무사해? 아직 함선에 있는 거지?","JPN":"みんな無事？　まだ艦船にいるんだよね？","ENG":"Is everyone okay? You’re still on the ship, right?","TWN":"大家都沒事吧？你們還在艦船裡嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"시그마! 헤론은 어떻게 됐어?","JPN":"シグマ！　ヘロンはどうなったの？","ENG":"Sigma! What happened to Heron?","TWN":"西格瑪！海倫怎麼樣？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"완전히 넋이 나간 상태야. 아까부터 미친 듯이 웃고만 있어.","JPN":"完全に正気を失ってる。さっきからずっと狂ったように笑ってるんだ。","ENG":"She's gone insane. All she does is laugh like crazy.","TWN":"精神狀態不太好，從剛才就像發狂似地狂笑。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"미안. 우리가 너무 늦었나 봐.","JPN":"ごめん。私たちが遅すぎたみたい。","ENG":"Sorry. I guess we were too late.","TWN":"對不起，我們好像晚了一步。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"기운내. 네가 사과할 일이 아니야, 시그마.","JPN":"頑張って。シグマが謝ることじゃないよ。","ENG":"Chin up. You don't have to apologize to us, Sigma.","TWN":"打起精神來，這不是你的錯，西格瑪。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"지금은 이 함선에서 탈출하는 게 먼저야. 탈출선이 있는 데로 가자.","JPN":"今はこの艦船から脱出するのが先だよ。脱出船のあるところに行こう。","ENG":"Getting off this ship is our number one priority. Let's head to the escape pods.","TWN":"現在最重要的是趕快逃離這艘艦船，先去有逃生船的地方吧！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"사람들이 이렇게나 많은데…… 제때 탈 수 있을까?","JPN":"こんなに人が多いのに……乗れるのかな？","ENG":"But there are so many people here... Do you think we'll be able to get on one in time?","TWN":"人這麼多……搭得到嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"……저희가 안내해 드리겠습니다. 손님 여러분.","JPN":"……私たちがご案内いたします。お客様。","ENG":"Dear guests... We will guide you.","TWN":"……各位客人，我帶你們去吧。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L29_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"<color=#ffd34c>그 목소리는…… 설마 휴스턴?</color>","JPN":"<color=#ffd34c>その声は……まさかヒューストン？</color>","ENG":"<color=#ffd34c>That voice... Is that Huston?</color>","TWN":"<color=#ffd34c>這個聲音是……休士頓？</color>"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"무슨 낯으로 우리 앞에 나타난 거야? 우리가 누구 때문에 이 고생을 했는데!","JPN":"どの面下げて私たちの前に現れたの？　誰のせいで苦労してると思ってる！","ENG":"What are you up to this time?! We're in this mess because of you!","TWN":"你還有什麼臉出現在我們面前？是誰害我們這麼辛苦的！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그만해, 리온. 저 사람 총에 맞았잖아.","JPN":"やめな、リオン。あの人も銃に撃たれてる。","ENG":"Enough, Liona. He's been shot.","TWN":"萊恩，別說了，你沒看到他中槍了嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"하지만……!","JPN":"でも……！","ENG":"But...!","TWN":"可是……！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"됐어. 이미 한 방 먹은 녀석을 뭐 하러 또 걷어차.","JPN":"もういい。すでに一発食らってるやつをまた蹴とばす必要はないよ。","ENG":"It's okay. There's no reason to kick someone who's already down.","TWN":"好了，既然他已經受到教訓，就不需要再對他落井下石。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"변명하지는 않겠습니다. 형님을 위해 기생충을 제거할 수 있다면 다른 건 상관없다고 생각했으니까요.","JPN":"言い訳はしません。兄貴のために寄生虫を除去することさえできれば、他はどうでもいいと思っていましたので。","ENG":"I won't make excuses. I thought that nothing else would matter if I could get rid of the parasites for Mr. Haven.","TWN":"我無話可說，只要能替大哥除掉寄生蟲，其他我都無所謂。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"<color=#ffd34c>저 바보가…….</color>","JPN":"<color=#ffd34c>あのバカが……</color>","ENG":"<color=#ffd34c>You fool...</color>","TWN":"<color=#ffd34c>那個傻瓜……</color>"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"그래서 이 멍청이가 혼자 다 안고 가겠답시고 날 독방에 처박아 둔 거고.","JPN":"それでこのバカが自分が責任を持つとか言って、私を独房に閉じ込めたわけね。","ENG":"And that's why this moron locked me up in a cell so he could take all the blame.","TWN":"所以這個笨蛋就把我關在房裡，打算自己承擔一切。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"일단 감속 장치는 어떻게 작동시키긴 했는데, 그것만 가지고 추락을 막기에는 무리야.","JPN":"とりあえずなんとか減速装置を作動させたけど、それだけでは墜落を止められない。","ENG":"I've restarted the decelerator, but it's not enough to stop the ship from crashing.","TWN":"雖然已經想辦法啟動減速裝置，但光靠那個還是無法阻止艦船迫降。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"조직원들 모두가 나서서 손님들부터 탈출선에 태우고 있다.","JPN":"組織員総出でお客様から先に脱出船に乗せている。","ENG":"All the other members are guiding our guests to the escape pods.","TWN":"現在所有員工全都在引導客人搭上逃生船，"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하지만 시간이 부족해. 게다가 도시에 헤이븐 랜드가 추락하면 큰일이 벌어질 거야.","JPN":"だが時間が足りない。しかも都市にヘイブンランドが墜落すると大変なことになるぞ。","ENG":"But there's not enough time. In addition, if Havenland crashes into the city, things are going to become much worse.","TWN":"但時間不夠，而且天堂樂園要是真的迫降的話，那個城市會完蛋的。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"모두 제 탓입니다. 제가 해결할 수 있다는 오만함 탓에 형님의 파라다이스를…….","JPN":"全て私のせいです。自力で解決できるという傲慢で、兄貴のパラダイスを……","ENG":"It's all my fault. Because of my arrogance I thought I could take care of this on my own. But in the end, your paradise...","TWN":"這全都怪我太驕傲，自以為能解決，才會害大哥的樂園……"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"어휴. 넌 진짜 이번 한 번만 누나가 봐 준다.","JPN":"まったく。このお姉さんが一度だけ許してやる。","ENG":"Ugh... You fool, I will forgive you this once.","TWN":"真是的，姊姊這次就先不跟你計較！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그거 다행이군. 두 번째는 없을지도 모른다는 게 문제지만.","JPN":"それはよかったな。二度目はないかもしれなということが問題だが。","ENG":"I’m glad to hear that. Although, there might not be another time for us.","TWN":"算你幸運，只是不知道還會有下次嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"흐흐……! 흐흐흐흐흐흐……!","JPN":"ふふ……！　ふふふふふふ……！","ENG":"Hehe...! Hehehehehe...!","TWN":"呵呵……！呵呵呵呵呵……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"다 없애 버릴 거야!! 다 같이 죽을 거라고!!","JPN":"全部消してやるわ！！　みんな死ねばいいのよ！！","ENG":"I'll destroy you all! You're going down with me!!","TWN":"我要把一切都毀掉！！我要把你們全殺掉！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"누나! 정신 차려! 제발 그만해!","JPN":"姉さん！　しっかりして！　お願いだからやめてよ！","ENG":"Sis! Stop this! Please!","TWN":"姊姊！你清醒一點！我拜託你！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"놔…… 이거 놔…… 놓으라고……!","JPN":"放して……放して……放しなさいったら……！","ENG":"Let... go...! I said, LET GO...!","TWN":"放……放開我……我叫你放開……！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"누나, 나도 누나와는 이제 두 번 다시 엮이고 싶지 않아.","JPN":"姉さん、僕ももう二度と姉さんとは関わりたくない。","ENG":"Sis, I don't want anything to do with you anymore.","TWN":"姊姊，我也不想再和你有任何牽扯。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"하지만…… 누나 말만 믿고 놀기만 하던 내 잘못도 분명히 있어.","JPN":"でも……姉さんの言葉だけを信じて、遊んでばかりだった僕の責任もあるんだ。","ENG":"Although I admit it was my fault to entrust you with everything while I was fooling around.","TWN":"但是……我也有錯，因為我只顧著玩，你說什麼我都信。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"내가 막을게!","JPN":"私が止める！","ENG":"I'll stop it!","TWN":"我會阻止它的！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"방금 추락을 막겠다고 한 거야? 시그마가?","JPN":"墜落を止めるって言ったの？　シグマが？","ENG":"Did Sigma just say she'll stop the ship from crashing?","TWN":"西格瑪，你剛說你要阻止艦船迫降嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아무리 애라도 그렇지, 이럴 때는 진지하게 생각해.","JPN":"子どもとはいえ、こういう時には真剣に考えないと。","ENG":"Stop kidding around and be serious about this.","TWN":"小孩子別亂說話，這種時候不要開玩笑！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 랜드는 보통 함선보다 몇 배는 커. 가능할 리 없잖아.","JPN":"ヘイブンランドは普通の艦船より何倍も大きいんだよ。できるわけないじゃん。","ENG":"There’s no way that's possible. Havenland is massive. Many times bigger than any ordinary ship.","TWN":"天堂樂園比普通的艦船還要大上好幾倍，你怎麼有辦法阻止。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"아냐, 할 수 있어. 아빠가 힘을 사용하게 허락해 준 이유가 있을 거야.","JPN":"ううん、できるよ。パパが力を使えるように許可してくれた理由があるはずだから。","ENG":"No, I can do it. Daddy gave me permission to use this power for a reason.","TWN":"是真的啦，我可以的。爸爸會答應讓我使用能力，一定是有原因的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"루트, 헤론을 부탁해!","JPN":"ルート、ヘロンをよろしく！","ENG":"Root! You deal with Heron!","TWN":"路特，海倫就拜託你囉！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"시, 시그마! 위험해!!","JPN":"し、シグマ！　危ないよ！！","ENG":"S-Sigma! It's too dangerous!!","TWN":"西…西格瑪！危險！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"저 아래에, 더 많은 사람들이 있어……!","JPN":"あの下に、人がもっとたくさんいるんだ……！","ENG":"There are a lot of people below us...!","TWN":"下面的人更多……！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"모두에게 알려 줄 거야. 이런 나쁜 짓으로는 행복해질 수 없다는 걸.","JPN":"みんなに教えてあげるんだ。悪いことしては幸せになれないってことを。","ENG":"I’m gonna show everyone. That you can't find happiness by doing bad things!","TWN":"我要告訴大家，用這種不好的行為是無法變幸福的！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그러니까……! 난 사람들을 지킬래!","JPN":"だから……！　私はみんなを守る！","ENG":"That's why...! I'm going to protect everyone!","TWN":"所以……！我要保護大家！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"하아아아아아아아아!!","JPN":"はああああああああ！！","ENG":"HAAAAAAAA!!","TWN":"哈啊啊啊啊啊啊！！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG_02"},{"id":"L35_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"잠깐…… 멈춘 건가?","JPN":"待って……止まった？","ENG":"Wait... Is it working?","TWN":"等等……停了嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"저, 정말이야? 시그마가 이 큰 함선을 혼자 막고 있다고?","JPN":"ほ、本当？　シグマがこの大きい艦船を一人で止めてるってこと？","ENG":"I-is this for real? Sigma's stopping this huge ship all by herself?","TWN":"真…真的嗎？西格瑪自己阻止這麼大的艦船？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"아무리 그래도 가능한 일이 있지! 공학자로서 인정 못 해!","JPN":"いくらなんでもあり得ない！　エンジニアとして認められない！","ENG":"How's that even possible?! As an engineer, I can't believe it!","TWN":"世界之大無奇不有！但理工科頭腦是無法理解的！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"그런 건 나중에 차차 고민해. 지금은 탈출선으로 가는 게 먼저야.","JPN":"それは後で考えろ。今は脱出船に向かうのが先だ。","ENG":"Let's think about that later. Right now, we need to head to the escape pods.","TWN":"這種事等之後再傷腦筋吧，現在當務之急是趕快去找逃生船！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"으그그그……! 너, 너무너무 무거워……!","JPN":"ぐぬぬぬ……！　め、めっちゃくちゃ重い……！","ENG":"Errrgh...! I-it's... so... heavy...!","TWN":"呃呃呃……！好重……！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"어떡하지? 에너지가 너무 빨리 줄어들어! 오래 못 버티겠어!","JPN":"どうしよう？　エネルギー消耗が早すぎ！　長く持たない！","ENG":"What do I do? I’m losing energy too fast! I won't be able to hold on much longer!","TWN":"怎麼辦？能源正在快速減少！沒辦法撐太久的！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루, 뭐 해!","JPN":"ルル、何してるんだよ！","ENG":"Lulu! Where do you think you're going?","TWN":"露露，你在幹嘛！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어서 와! 늦었다간 탈출선이 없을 수도 있어!","JPN":"早くおいで！　遅れたら脱出船がなくなっちゃう！","ENG":"C'mon! There might not be an escape pod left if we're late!","TWN":"快過來！萬一動作太慢會搭不到逃生船的！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"가야 해, 글린다.","JPN":"行かなきゃ、グリンダ。","ENG":"I need to go, Glinda.","TWN":"我要去，格琳達。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이 상황에 또야? 당장 죽게 생겼는데 악몽 꾸는 사람이 어디 있다고!","JPN":"こんな状況でまた？　今すぐ死ぬかもしれないのに悪夢を見てる人なんていないよ！","ENG":"That again?! No one's gonna have a nightmare when we're all about to plunge to our deaths!","TWN":"這種時候還來？這種生死交關的時刻，誰有閒情逸致做惡夢啦！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"하지만 이 함선이 떨어지면 더 많은 사람들에게 악몽이 스며들 거야.","JPN":"でもこの艦船が墜落すればもっと多くの人に悪夢が染み入ることになるよ。","ENG":"But if this ship falls, the nightmare will spread to more people.","TWN":"萬一艦船迫降的話，惡夢會擴散至更多人的！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그래서? 네가 시그마를 돕는다고 추락을 막을 수 있을 거 같아?","JPN":"それで？　アンタがシグマを手伝うとして、墜落を止められるとでも思ってる？","ENG":"So? How are you gonna help Sigma stop it from crashing?","TWN":"所以呢？你覺得你可以阻止迫降嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"자! 말도 안 되는 소리 하지 말고 얼른!","JPN":"ほら！　バカ言ってないで早く！","ENG":"See? Don’t be absurd, and hurry up!","TWN":"快點！不要再說那些莫名其妙的話，快過來！"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"할 수 있어. 시그마와 힘을 합치면.","JPN":"できるよ。シグマと力を合わせれば。","ENG":"We can stop it. Sigma and I, together.","TWN":"可以的，只要我和西格瑪的力量加在一起。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……할 수 있다니? 방금 내가 제대로 들은 거 맞아?","JPN":"……できるって？　聞き間違いじゃないよね？","ENG":"Stop it...? Did I hear that right?","TWN":"……可以什麼啦？我剛有聽錯嗎？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"너는 한결 같은 사람이야. 가시를 세우지만 마음씨는 상냥해.","JPN":"グリンダはいつも変わらないね。ツンツンしてても心は優しい。","ENG":"You're the same as always, Glinda. Your claws are always out, but you have a kind heart.","TWN":"你是個表裡如一的人，雖然帶刺心地卻很善良。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그래서 고마웠어.","JPN":"だからありがたく思ってたの。","ENG":"I've always been grateful for that.","TWN":"我很感謝你。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"누군가가 자신보다 나를 더 아껴준다는 거, 처음 느껴봤거든.","JPN":"誰かが自身より私をもっと大事に思ってくれるのって、初めてのことだったから。","ENG":"It was the first time I saw someone who cared about me more than they did about themselves.","TWN":"你讓我第一次感受到，有人比我更在乎我自己。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루, 너…….","JPN":"ルル、アンタ……","ENG":"Lulu...","TWN":"露露，你……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"나는 항상 악몽이었어, 글린다.","JPN":"私はいつも悪夢だったよ、グリンダ。","ENG":"I've always been the nightmare, Glinda.","TWN":"格琳達，我原是惡夢。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"하지만 너에게만큼은, 상쾌한 아침을 맞이해 주는 꿈으로 남을래.","JPN":"でもあなたにとってだけは、爽やかな朝を迎えさせてあげられる夢でありたい。","ENG":"But I want to remain a dream to you, warm like the morning sun.","TWN":"但至少面對你，我希望是迎接美好早晨的夢。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>저리 비켜! 내가 먼저 탈 거야!</color>","JPN":"<color=#ffd34c>邪魔するな！　私が先だ！</color>","ENG":"<color=#ffd34c>Out of my way! I'm getting on first!</color>","TWN":"<color=#ffd34c>給我走開！我要先搭！</color>"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사람 살려!! 이런 데서 죽기 싫어!</color>","JPN":"<color=#ffd34c>助けて！！　こんなところで死にたくない！</color>","ENG":"<color=#ffd34c>Somebody, please!! I don't wanna die like this!</color>","TWN":"<color=#ffd34c>救命啊！！我不想死在這裡！</color>"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"으으, 안 돼……! 더는 못 버티겠어……!","JPN":"うう、ダメ……！　もう耐えられない……！","ENG":"Nngh...! I-I can't...! Stop it any more...!","TWN":"呃呃，不行……！我撐不下去了……！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"미안해, 아빠……! 난 아빠 딸인데……!","JPN":"ごめんね、パパ……！　私はパパの娘なのに……！","ENG":"I'm so sorry, Daddy...! Your girl has–","TWN":"爸爸，對不起……！我是爸爸的女兒卻……！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"……어라?","JPN":"……あれ？","ENG":"…Oh?","TWN":"……嗯？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"달님이…… 없어졌네?","JPN":"お月様が……消えちゃった？","ENG":"Where did the moon... go?","TWN":"月亮……消失了？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……잠깐. 가속도가 줄어들었어.","JPN":"……ちょっと待って。加速が緩やかになった。","ENG":"...Wait. We're slowing down.","TWN":"……等等，速度好像慢下來了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼 시그마가 성공한 거야?","JPN":"じゃあ、シグマが成功したの？","ENG":"Does that mean Sigma stopped it?","TWN":"意思是西格瑪成功了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시, 수아야!","JPN":"ドロシーちゃん、コトリちゃん！","ENG":"Dorothy! Skia!","TWN":"桃樂絲，蘇亞！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"밖을 봐 봐! 뭔가……! 뭔가……!","JPN":"外を見て！　何か……！　何か……！","ENG":"Look out the window! Something...! Something...!","TWN":"你們看外面！好像……！好像……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"뭔가 엄청 복슬복슬한 게 나타났어!","JPN":"何かすごくふわふわしたものが現れたよ！","ENG":"Something big and fluffy just appeared!!","TWN":"好像有什麼毛茸茸的東西出現！"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"우와아! 엄청 커다란 양이다! 털이 푹신푹신해!","JPN":"うわあ！　めっちゃ大きな羊さんだ！　毛がふわふわ！","ENG":"Woooow! It's a giant sheep! The wool is so soft and fluffy!","TWN":"哇喔！超大隻的羊欸！毛好軟喔！"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"태워 줘서 고마워, 양아! 그런데 넌 어디서 왔어?","JPN":"乗せてくれてありがとう、羊さん！　でもあなたはどこから来たの？","ENG":"Thanks for the ride, sheep buddy! But where did you come from?","TWN":"羊羊，謝謝你載我！不過你是從哪來的？"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"후후, 칭찬해 줘서 고마워. 시그마.","JPN":"ふふ、褒めてくれてありがとう。シグマ。","ENG":"Hu hu, thanks for the compliment, Sigma.","TWN":"呵呵，謝謝你的讚美，西格瑪。"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"루루? 방금 그 목소리, 루루 맞지?","JPN":"ルル？　今の声、ルルだよね？","ENG":"Lulu? That voice... It’s you isn’t it?","TWN":"露露？剛剛的聲音是露露對吧？"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응. 지금 이 모습이 본래의 나야.","JPN":"うん。今のこの姿が本当の私なの。","ENG":"Yes. This is my original form.","TWN":"嗯，這才是我原本的樣子。"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"무척 무거운 함선이네. 오래 버티긴 힘들겠어. ","JPN":"とても重い艦船だね。長くは持たないかも。 ","ENG":"This ship is really heavy. I don't think I'll be able to stop it for very long. ","TWN":"這艘艦船好重喔，撐那麼久很辛苦吧。"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"도와 주러 왔어. 혼자서 힘내고 있었다니, 정말 대견하다.","JPN":"助けに来たよ。一人で頑張ってたなんて、本当に偉いね。","ENG":"I came to help. I'm amazed you were able to slow this thing down all by yourself.","TWN":"我是來幫你的，你好厲害，可以自己堅持那麼久。"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그치만 이제 곧 한계야. 에너지가 다 떨어졌어.","JPN":"でももうすぐ限界なの。エネルギーが尽きちゃった。","ENG":"But I'm reaching my limit. I'm all out on energy.","TWN":"可是我差不多到極限了，能源都用光了。"},"stage":{"bg":"HAVEN_04","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"앗! 저 소리, 함선 쪽에서 났어!?","JPN":"あっ！　あの音、艦船の方からじゃない！？","ENG":"Huh?! Did that explosion come from the ship?!","TWN":"唔！那個聲音，是從艦船裡傳出來的嗎！？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"함선이 무너지려고 해. 동력을 잃어서 무게를 견디지 못하나 봐.","JPN":"艦船が崩れようとしてるの。動力を失って、重さに耐えられなくなったみたい。","ENG":"The ship's lost its power and can't withstand the weight. It's going to fall.","TWN":"艦船要塌了，因為失去動能，無法支撐重量的樣子。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그럼 안 돼! 안에 타고 있는 사람들도, 도시 사람들도 전부……!","JPN":"ダメ！　中に乗ってる人たちも、都市の人たちも全部……！","ENG":"No! There are people on that ship, and even more down below...!","TWN":"不可以！那艦船裡的人，和城裡的人全部都會……！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"차분하게 생각해, 시그마. 네가 지닌 힘을 잊지 마.","JPN":"落ち着いて考えて、シグマ。あなたの力を忘れないで。","ENG":"Stay calm and think, Sigma. Don't forget about your strength.","TWN":"西格瑪，冷靜點，不要忘記你擁有的力量。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"아……!","JPN":"あ……！","ENG":"Ah...!","TWN":"嗯……！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"하지만 에너지가 부족해. 이것만 가지고는 할 수 없어.","JPN":"でもエネルギーが足りないよ。これだけじゃできないんだ。","ENG":"But I don’t have enough power. I can’t do it with this little.","TWN":"可是能源不足也派不上用場。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그러니? ","JPN":"そう？ ","ENG":"What then? ","TWN":"所以呢？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그렇다면 다른 사람들에게 물어 보면 어떨까?","JPN":"それなら他の人たちに聞いてみればどうかな？","ENG":"Why don’t we ask other people for help?","TWN":"那還是要問問其他人呢？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"퇴근길 위로, 커다란 양 위에 올라탄 밝고 작은 불빛이 함선을 떠받치고 있었다.","JPN":"退勤後の帰り道、上空に大きな羊の上に乗った明るくて小さな光が艦船を支えていた。","ENG":"On my way home, I saw a small light on top of a giant sheep holding up a ship.","TWN":"下班路上，巨大的羊上方，閃爍的微小火光支撐著艦船。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"대피 경보 따위 개나 줘 버려. 도망쳐 봐야 어디까지 가겠어.","JPN":"退避警報なんてクソ食らえ。どうせ遠くまでは逃げられない。","ENG":"Who cares about the sirens? Where am I even supposed to evacuate to?","TWN":"避難警報說給狗聽吧，是能逃到哪裡去。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그럴 시간에 차라리 저 광경을 좀 더 눈에 담고 싶어.","JPN":"その時間にむしろあの光景をもっと見ておきたいんだ。","ENG":"I'd rather spend a little more time looking at what's happening in the sky.","TWN":"有時間逃，不如再多看幾眼這樣的光景。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"힘에 부친다는 게 느껴져. 불빛이 희미해져 가고 있어.","JPN":"力が及ばないということがわかる。光りがどんどん弱くなっていく。","ENG":"I feel it being overpowered, and the light gets dimmer.","TWN":"似乎有點吃力，火光越來越微弱。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"하지만…… 사는 대로 사는 내가 말하긴 부끄럽지만.","JPN":"でも……適当に生きている僕がこんなことを話すのは恥ずかしいけど。","ENG":"And even though I'm a little embarrassed to say this as I just go with the flow in life...","TWN":"不過……雖然得過且過的我這麼說有點羞愧，"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"조금만 더, 아주 조금만 더 힘을 내 줘.","JPN":"もう少しだけ、もう少しだけ頑張って。","ENG":"Hang in there just a little longer! I'm rooting for you!","TWN":"但撐一下，再撐一下就好。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"안녕! 난 시그마! 아빠 딸이야!","JPN":"こんにちは！　私はシグマ！　パパの娘だよ！","ENG":"Hi! I'm Sigma! Daddy's girl!","TWN":"哈囉！我是西格瑪！是爸爸的女兒！"},"stage":{"bg":"HAVEN_03","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"핸드폰에서 밝은 목소리가 들려왔다.","JPN":"ケータイから明るい声が聞こえてきた。","ENG":"I hear a bright voice coming from my phone.","TWN":"手機傳來一個爽朗的聲音。"},"stage":{"bg":"HAVEN_03","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"미안해. 도시로 떨어지는 함선을 세우려고 했는데, 나랑 친구만으로는 힘이 부족해.","JPN":"ごめんね。都市に落ちかかってる艦船を止めようとしたけど、私と友達の力だけでは足りないの。","ENG":"I’m sorry. My friend and I tried to stop the ship from falling on this city, but we aren't strong enough.","TWN":"不好意思，我想阻止艦船掉到城市裡，但光靠我和朋友的力量不太夠。"},"stage":{"bg":"HAVEN_03","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그래서 도시의 전력을 잠깐만 빌리려고 해.","JPN":"それで、都市の電力をちょっと借りようと思うんだ。","ENG":"So we're thinking of borrowing the city's power for just a moment.","TWN":"所以想借用一下這個城市的電。"},"stage":{"bg":"HAVEN_03","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"잠깐이면 되니까! 응?","JPN":"ちょっとでいいから！　ね？","ENG":"It won't take long! So please let us borrow it?","TWN":"借一下就好！可以嗎？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"화면에 떠오른 것은 승낙과 거절의 뜻을 지닌 두 개의 단추.","JPN":"画面に浮かんだのは承諾と拒否の意味を持っている二つのボタン。","ENG":"Two buttons appear on my screen, one to accept and one to decline.","TWN":"畫面上出現二個按鈕，一個是同意，一個是拒絕。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"무심코 주위를 둘러 보니 다른 운전자들도 핸드폰을 들여다보고 있다.","JPN":"何気なく周りを見回すと、他のドライバーもみんなケータイを覗き込んでいる。","ENG":"I look up to see the other drivers, and they're also looking down at their phones.","TWN":"無意間環顧四周，其他駕駛人也都在看手機。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"나는…… 오늘 정말 많은 일을 겪었는걸.","JPN":"私……今日は本当にたくさんのことがあったんだ。","ENG":"A lot of things... happened to me today.","TWN":"我……今天真的遇到超多事的！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"싫은 일도 있었지만 좋은 일도 있었어! 그래서 내일이, 매일매일이 기대돼!","JPN":"イヤなこともあったけど、いいこともあったんだよ！　だから明日が、毎日が楽しみ！","ENG":"Some things made me sad, but others were enjoyable! That's why I look forward to seeing what tomorrow has in store for me every day!","TWN":"雖然有討厭的事，但也有開心的事！所以我每一天都很期待！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그 기분을 앞으로도 모두가 알아 주면 좋겠으니까……! 부탁해!","JPN":"その気持ちをこれからもみんなにわかってほしいから……！　お願い！","ENG":"And I want all of you to feel what I feel... So won’t you please help me?","TWN":"我希望大家以後也都能知道這種心情，所以……！拜託！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"나는 다른 모두가 누른 단추를 눌렀다.","JPN":"僕は他の全員が押したボタンを押した。","ENG":"I pressed the same button as everyone else.","TWN":"我和大家都按下相同的按鈕。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"적어도 내일은, 저 아이 덕분에 오늘보다 재밌겠다고 생각하면서.","JPN":"少なくとも明日は、あの子のおかげで今日より楽しくなりそうだって思いながら。","ENG":"Hoping that thanks to that kid, at least tomorrow will be a better day.","TWN":"至少明天，託她的福可以過得比今天更開心。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>도와 줄게.</color>","JPN":"<color=#ffd34c>助けてあげるよ。</color>","ENG":"<color=#ffd34c>I will help you.</color>","TWN":"<color=#ffd34c>我也來幫忙！</color>"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"이대로는 헤이븐 랜드가 공중 분해될 거야! 뭐라도 꽉 잡아!","JPN":"このままではヘイブンランドが空中分解するよ！　何でもいいから掴んで！","ENG":"Havenland's gonna blow to smithereens at this rate! Hold on to something tight!","TWN":"這樣下去，天堂樂園會在空中解體的！大家找個東西抓緊！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아니야.","JPN":"違う。","ENG":"No.","TWN":"不用。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"무슨 소리야! 정신……!","JPN":"何を言ってるんだ！　しっかり……！","ENG":"What do you mean, \\"no\\"?! Get–!","TWN":"你在說什麼！你……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"……어?","JPN":"……ん？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>진단. 시그마 프로토콜에 의한 파손 부분 수복 완료. 메인 시스템 재기동.</color>","JPN":"<color=#ffd34c>診断。シグマ・プロトコルによる破損を部分修復完了。メインシステムを再起動。</color>","ENG":"<color=#ffd34c>Diagnosing. Partial restoration through Sigma Protocol, complete. Main system reactivated.</color>","TWN":"<color=#ffd34c>診斷，西格瑪協定損壞部分已修復完畢，主要系統重新啟動。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>꿈과 희망의 낙원, 헤이븐 랜드에 오신 승객 여러분을 환영합니다.</color>","JPN":"<color=#ffd34c>夢と希望の楽園、ヘイブンランドへお越しくださった乗客の皆様、ようこそ。</color>","ENG":"<color=#ffd34c>Welcome to Havenland! The paradise of your hopes and dreams!</color>","TWN":"<color=#ffd34c>歡迎各位乘客來到夢想和希望的天堂樂園。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>평형 조정 중 약간의 흔들림이 있을 수 있습니다. 조심해 주세요.</color>","JPN":"<color=#ffd34c>平衡調整中、少々揺れることがございます。お気を付けください。</color>","ENG":"<color=#ffd34c>There might be some slight turbulence as we stabilize. Please watch your step.</color>","TWN":"<color=#ffd34c>船身正在調整平衡，會有點搖晃，請各位乘客小心。</color>"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하, 하하…… 하……","JPN":"は、はは……は……","ENG":"Hah. Hah hah... Hah...","TWN":"哈哈哈……哈……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"뭐야, 이거? 왜 추락하지 않는 건데? 왜 박살나지 않는 건데?","JPN":"何、これ？　どうして墜落しないの？　どうして粉々にならないのよ？","ENG":"What?! Why did it stop falling? Why is it not crashing to the ground?","TWN":"怎麼會這樣？為什麼沒有迫降？為什麼沒有解體？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이게 무슨 해피 엔딩만 찾는 동화야……?","JPN":"ハッピーエンドしかないおとぎ話でもなし……","ENG":"What is this?! Some sort of fairy tale with a happy ending...?","TWN":"這是什麼童話般幸福快樂的結局……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"맞아. 동화야, 누나. 오늘만큼은.","JPN":"そうだよ。おとぎ話なんだ、姉さん。今日だけはね。","ENG":"Yup. It's a fairy tale, Sis. At least for tonight.","TWN":"沒錯，姊姊，就是童話，至少今天是。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그러니까…… 악당답게 죗값을 치르러 가자.","JPN":"だから……悪党らしく罪滅ぼしに行こう。","ENG":"So... It's time for the villains to pay.","TWN":"去吧……付出壞人應付的代價！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"언제까지나 동화 속에 틀어박혀 살 수는 없잖아.","JPN":"いつまでもおとぎ話の中で閉じこもって生きるわけにはいかないからね。","ENG":"We can't hide inside a fairy tale forever.","TWN":"總不能一直躲在童話裡吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"와아! 루루, 우리가 해냈어!","JPN":"わあ！　ルル、やったよ！","ENG":"Wooow! Lulu! We did it!","TWN":"哇！露露，我們辦到咧！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"도시 사람들 전부가 힘을 빌려 주니까, 잠깐만 받았을 뿐인데도 든든한 기분이야.","JPN":"都市の人たちみんなが力を貸してくれたから、ちょっと電力をもらっただけなのに心強い気分だよ。","ENG":"Even if it was for just a brief moment, I felt reassured when everyone in the city offered me their support.","TWN":"全城的人都幫我們，雖然只是一下下，卻很給力呢！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응. 저 거대한 함선을 눈 깜짝할 사이에 원래대로 되돌려 버렸네.","JPN":"うん。あの巨大は艦船をあっという間に元どおりに戻しちゃったね。","ENG":"Yes. Even that giant ship got fixed in the blink of an eye.","TWN":"嗯，眨眼間，那麼大艘的艦船就恢復原樣咧！"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"히히, 도시에 있는 사람들에게는 어떻게 고맙다고 전해 줄까?","JPN":"へへ、都市にいる人たちにどうやってありがとうって伝えようかな？","ENG":"Hehe. How do you think I should thank them?","TWN":"嘻嘻，該怎麼向城市裡的人表達感謝呢？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"편지가 좋을까? 아니면 전광판에 깜짝 등장?","JPN":"手紙？　それともスクリーンにドッキリで登場する？","ENG":"Would a letter be okay? Or maybe I should pop up in one of their billboards!","TWN":"要寫信嗎？還是在LED板上出現一下？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"표현하지 않아도 전해질 거야. 그 사람들도 시그마 너만큼 고마워하고 있을 테니까.","JPN":"表現しなくても伝わるはずだよ。あの人たちもシグマくらいありがたく思ってるはずだから。","ENG":"They will know how grateful you are, even if you don’t say anything. Besides, I'm sure they will be thanking you more.","TWN":"不用刻意表達，他們也能感受到的，因為他們現在應該也很感謝你。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"루루, 갑자기 네 몸이 투명해 보여.","JPN":"ルル、体がいきなり透けてみえるよ。","ENG":"Lulu...? Why can I see through you?","TWN":"露露，你的身體突然變透明咧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"피곤해서 그래. 본래 모습으로 돌아가려면 기운이 아주 많이 필요하거든.","JPN":"疲れたからだよ。本来の姿に戻るためには気力がいっぱい必要なの。","ENG":"I’m tired, that’s all. It takes a lot of energy to turn back into my original form.","TWN":"因為我太累的關係，要恢復原本的樣子，會需要花很多力氣。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그러면 어떡해? 백 밤 자면 나아?","JPN":"じゃあ、どうするの？　百回寝たら治る？","ENG":"Then what do you do? Will you get better if you sleep a hundred nights?","TWN":"那怎麼辦？睡一百天的話可以嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"사람들이 나쁜 꿈을 꿀 때면.","JPN":"人が悪い夢を見るたびに。","ENG":"When people get nightmares...","TWN":"前提是人有做惡夢。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"나는 달이 없는 밤, 긴 다리로 지붕 위를 넘어다니면서 꿈을 앗아가던 이물이니까.","JPN":"私は月のない夜、長い足で屋根の上を歩きながら夢を奪っていた異物だから。","ENG":"I am the moonless night. I am the stranger who crosses a long bridge up in the sky, taking people's dreams.","TWN":"因為我是在沒有月亮的晚上，用長長的腳越過屋頂，把夢奪走的異物。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"꿈을……?","JPN":"夢を……？","ENG":"Dreams...?","TWN":"把夢……？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응. 우리는 모두 그래.","JPN":"うん。私たちはみんなそうなの。","ENG":"Yes. We're all like that.","TWN":"嗯，我們都這樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"오로치도. 나도. 패러독스도.","JPN":"オロチも。私も。パラドックスも。","ENG":"Orochi, me, and Paradox.","TWN":"無論是大蛇，或我，或悖論都是。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"동류들과 다르게, 각자의 이유로 어울려 사는 길 대신 옛날 그 시절에 남아 버렸어.","JPN":"みんなとは違って、それぞれの理由で一緒には暮らさずに昔の時代に残っちゃったの。","ENG":"Unlike my peers, we all went our separate ways instead of living together, but we remain in the old days because of our own reasons.","TWN":"我和同類不同，因為各自的理由沒有選擇合適的路，而是留在以前。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그러니까…… 잠시 떠나야 해.","JPN":"だから……しばらく離れないと。","ENG":"So... I have to leave for a while.","TWN":"所以……我要暫時離開。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"나 때문에 다른 애들도 깨어나면 모두에게 폐를 끼칠 테니까.","JPN":"私のせいで他の子たちも目を覚めたらみんなに迷惑になるはずだから。","ENG":"I don't want the others to wake up because of me.","TWN":"要是因為我而喚醒其他同類，對大家都有害。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그치만 루루가 떠나면 글린다가 슬퍼할 거야.","JPN":"でもルルがいなくなるとグリンダが悲しむよ。","ENG":"But if you leave, Glinda will be sad, Lulu.","TWN":"可是露露離開的話，格琳達會難過的。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"지금의 내가 곁에 있으면 아이들에게는 괴로운 앞날이 펼쳐져.","JPN":"今の私がそばにいても、子どもたちには辛い未来しか待ってない。","ENG":"If I stay, other children here will suffer.","TWN":"我現在留下的話，以後只會帶給她們痛苦。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그럼 안녕. 너희 아빠에게 안부 전해 줘.","JPN":"それじゃあ、さよなら。あなたのパパによろしく伝えてね。","ENG":"Goodbye for now. Say hello to your dad for me.","TWN":"再見，代替我向你爸爸問好。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"루루, 우리 아빠랑 아는 사이였어?","JPN":"ルル、私のパパと知り合いだったの？","ENG":"Lulu, you know my Daddy?","TWN":"露露，你認識我爸爸嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그럼. 내가 악몽을 거두게 된 계기인걸.","JPN":"もちろん。私が悪夢を取り込むようになったきっかけなの。","ENG":"Of course. He's the reason I started harvesting nightmares.","TWN":"當然，他可是我收取惡夢的動機呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"무섭지만 다정하고, 강하지만 아픔도 많은 사람…….","JPN":"怖いけど優しい、強いけど傷も多い人……","ENG":"He's kind, yet scary. Strong, but is also in pain...","TWN":"他是既可怕又親切，既強悍又多愁善感的人……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"그 사람에게는 네가 필요해. 시그마. 항상 옆에서 힘이 되어 주길 바래.","JPN":"あの人にはあなたが必要よ、シグマ。いつもそばで力になってほしい。","ENG":"He needs you, Sigma. I want you to always stay by his side and help him.","TWN":"西格瑪，他需要你，希望你常常在他身邊，成為他的力量。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"……응! 약속할게, 루루!","JPN":"……うん！　約束するよ、ルル！","ENG":"...Okay! I promise, Lulu!","TWN":"……好！我答應你，露露！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"울지 않아 주는구나. 시그마는 착해.","JPN":"泣かないね。シグマはいい子だよ。","ENG":"You're holding back your tears for me. You are such a kind girl, Sigma.","TWN":"你沒有哭呢，西格瑪好乖。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"잠시 떠날 뿐이잖아? 그럼 다시 만날 수 있어!","JPN":"しばらく離れているだけでしょ？　じゃあ、また会える！","ENG":"Because you’ll only be gone for a little while, right? Then we'll be able to see each other again!","TWN":"你只是暫時離開而已不是嗎？那我們會再見面的！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"다시 만날 때는, 오늘보다 훨씬 재밌게 놀자!","JPN":"また会ったら、今日よりもっと楽しく遊ぼう！","ENG":"When we do, let's have more fun than we had today!","TWN":"下次見面時，要比今天玩得更開心喔！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_SIGMA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};